    ('cat_first_word_picture_books', 3, 3, 'visible', true, true, 'Best for flap and name', 'Dear Zoo', 'Rod Campbell', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/dear-zoo-rod-campbell/9781407030678', NULL, '£7.99', 'in_stock', 'Board book classic', 'A lift the flap board book of animals sent by the zoo, inviting toddlers to open, look and name each creature on a short shared read.', 'Flaps turn naming into a job with a clear next move. Dear Zoo keeps the animal list familiar without a photo catalogue. Best when first word catalogues already cover pointing and you want a short story style naming pattern with flaps.', 'Flap and name animals.', 'Flaps tear; supervise.', 'buy', true, 'Board book gift.', 'Skip if Dear Zoo already lives on the shelf.', 'Board book; supervise flaps and patches.', 'good', ARRAY['uk.bookshop.org dear-zoo']::text[], 'none'),
