    ('cat_first_word_picture_books', 7, 7, 'visible', true, true, 'Best for dino texture naming', 'That''s Not My Dinosaur', 'Fiona Watt', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/that-s-not-my-dinosaur-fiona-watt/9781474916222', NULL, '£6.99', 'in_stock', 'Touchy-feely board book', 'A touchy feely dinosaur board book with patches to feel while you name textures and simple describing words on short looks.', 'Touch patches keep describing words going when photo catalogues lose them. Dinosaur pages give a different theme from everyday object lists on the sofa. Choose when Ladybird touch books already cover one line and you want Usborne style texture naming.', 'Dino texture naming.', 'Touch patches wear.', 'buy', true, 'Board book gift.', 'Skip if a That’s Not My title already sits in the basket.', 'Board book; supervise flaps and patches.', 'good', ARRAY['uk.bookshop.org thats-not-my-dinosaur']::text[], 'none'),
