    ('cat_open_cup', 3, 3, 'visible', true, true, 'Best for first Explora free flow', 'Tommee Tippee Explora First Cup 2 Pack', 'Tommee Tippee', 'Boots', 'https://www.boots.com/tommee-tippee-explora-first-cup-2-pack-10202518', NULL, '£6.99', 'in_stock', '4 months +', 'A two pack of Tommee Tippee Explora first cups with soft free flow spouts and handles sized for early independent sips.', 'A two pack means one cup at home and one in the bag without hunting lids. Explora free flow stays kinder to gums than hard valves. Best when Vital Baby stock is thin and you want a familiar high street free flow pair.', 'Free-flow Explora pair.', 'Not open rim.', 'buy', true, 'Useful two pack.', 'Skip if Explora cups already fill the cupboard.', 'Supervise.', 'good', ARRAY['boots.com tommee-tippee-explora-first-cup-2-pack']::text[], 'none'),
    ('cat_open_cup', 4, 4, 'visible', true, true, 'Best for single First Cup spare', 'Tommee Tippee First Cup', 'Tommee Tippee', 'Boots', 'https://www.boots.com/tommee-tippee-first-cup-10202516', NULL, '£4.99', 'in_stock', '4 months +', 'One Tommee Tippee First Cup with soft spout and chunky handles, useful as a spare when the main free flow pair already lives at home.', 'Bag days do not always need a second full set on the shelf. This single First Cup covers travel or grandparent visits without another two pack. Choose after Explora already handles the kitchen and you only want one extra spout cup.', 'Single free flow spare.', 'Second Tommee Tippee; brand cap full.', 'buy', true, 'Small spare gift.', 'Pick two pack OR single first.', 'Supervise.', 'good', ARRAY['boots.com tommee-tippee-first-cup']::text[], 'none'),
    ('cat_open_cup', 5, 5, 'visible', true, true, 'Best for soft spout trainer spare', 'Philips Avent Natural Response Trainer Cup 150ml', 'Philips Avent', 'Boots', 'https://www.boots.com/philips-avent-natural-response-trainer-cup-150ml-10275508', NULL, '£8.99', 'in_stock', '6 months +', 'A 150ml Philips Avent trainer cup with a soft spout and handles for early sips when you want a third brand beside Doidy and Tommee Tippee.', 'Brand variety helps when Boots stock of free flow cups runs thin. Avent keeps a soft spout and small capacity for supervised table drinks. Best as a spare trainer path once open Doidy and free flow Explora already cover the main jobs.', 'Soft spout trainer spare.', 'Trainer spout; not a true open rim. Check free flow vs valve on the live SKU.', 'buy', true, 'Practical spare.', 'Skip if Avent trainers already fill the cupboard.', 'Supervise.', 'good', ARRAY['boots.com philips-avent-natural-response-trainer']::text[], 'check_age_fit'),
    ('cat_ramp_rolling_toys', 1, 1, 'visible', true, false, 'Best for flip and chase', 'Quercetti FlipCar Racetrack', 'Quercetti', 'Toytastic', 'https://toytastic.co.uk/product/quercetti-flipcar-racetrack/', NULL, '£28.99', 'in_stock', '18 months +', 'A short track set with chunky flip cars that race, tip and tumble after a push, sized for toddler hands on the floor.', 'At sixteen to eighteen months, testing what happens often means a push, a roll and a delighted chase. FlipCar keeps the run short enough for living-room floors without a huge circuit. Best near eighteen months when a single ball already feels too simple and hands want a car that flips.', 'Ramp rolling with flip cars.', '18m+ overlaps band at the top only.', 'buy', true, 'Bigger gift box.', 'Skip if a short car ramp already lives by the sofa.', 'Supervise small track pieces.', 'good', ARRAY['toytastic.co.uk quercetti-flipcar-racetrack']::text[], 'check_age_fit'),
    ('cat_ramp_rolling_toys', 2, 2, 'visible', true, true, 'Best for drop and sound roll', 'Quercetti Migoga Tower Sound', 'Quercetti', 'Toytastic', 'https://toytastic.co.uk/product/quercetti-migoga-tower-sound/', NULL, '£25.99', 'in_stock', '18 months +', 'A clear spiral tower where large balls drop with a short sound trail, inviting toddlers to feed, watch and chase the roll.', 'When the question is what happens if I drop this, a sound tower answers out loud. Migoga Sound keeps balls large and the path visible on the floor. Choose when FlipCar is too heavy on track pieces and you want drop and roll on a small footprint.', 'Drop and roll tower.', 'Second Quercetti; brand cap full. 18m+ upper overlap.', 'buy', true, 'Cause and effect gift.', 'Skip if Spiral Tower already bought for stacking play.', 'Supervise assembly.', 'good', ARRAY['toytastic.co.uk quercetti-migoga-tower-sound']::text[], 'check_age_fit'),
    ('cat_ramp_rolling_toys', 3, 3, 'visible', true, true, 'Best for soft hallway roll', 'Scrunch Ball', 'Scrunch', 'Adventure Toys', 'https://www.adventuretoys.co.uk/scrunch-ball/', NULL, '£12.99', 'in_stock', 'Toddler soft play ball', 'A light soft PVC ball you inflate with a straw, grippy enough for toddler throws and indoor chase without a heavy sports bounce.', 'Ramp days still need a free roll that invites a toddle after it. Soft Scrunch weight keeps hallway chase kind on shins and shelves. Bring it out when track sets feel too fussy and you want one ball that packs flat for the bag.', 'Soft free roll for chase.', 'Also listed under soft balls category.', 'buy', true, 'Easy wrap.', 'Skip a second soft ball if one already gets daily chase.', 'Adult inflate first uses.', 'good', ARRAY['adventuretoys.co.uk/scrunch-ball']::text[], 'none'),
    ('cat_ramp_rolling_toys', 4, 4, 'visible', true, true, 'Best for grasp and roll set', 'Bigjigs Activity Balls', 'Bigjigs', 'Adventure Toys', 'https://www.adventuretoys.co.uk/big-jigs-activity-balls/', NULL, '£9.99', 'in_stock', '12 months +', 'A set of soft silicone activity balls with open textures for grasp, squash and short rolls across carpet or hard floors.', 'Some rolling days are about the grab as much as the chase. Bigjigs silicone balls stay soft while textures invite a firmer hold. Useful when one Scrunch already covers hallway distance and you want a set you can leave in two rooms.', 'Graspable roll set.', 'Shorter roll than Scrunch.', 'buy', true, 'Small set gift.', 'Not a second soft PVC ball.', 'Supervise mouthing.', 'good', ARRAY['adventuretoys.co.uk big-jigs-activity-balls']::text[], 'none'),
    ('cat_ramp_rolling_toys', 5, 5, 'visible', true, true, 'Best for quiet fabric roll', 'Les Deglingos Melimelos Activity Ball', 'Les Deglingos', 'Toytastic', 'https://toytastic.co.uk/product/les-deglingos-activity-ball-melimelos-the-deer/', NULL, '£18.99', 'in_stock', 'Birth to 18 months', 'A soft fabric activity ball with tags and textures, light enough to roll a short way and easy to pick up again after a crawl chase.', 'Hard floors can make plastic rolls too loud for evening play. This fabric ball keeps the chase soft and the grab interesting with tags. Best when silicone and PVC balls already sit in the basket and you want a quieter indoor option that still overlaps this band.', 'Quiet fabric roll.', 'Birth–18m ends at band max.', 'buy', true, 'Soft gift.', 'Skip if a fabric activity ball already gets daily use.', 'Check tags for wear.', 'good', ARRAY['toytastic.co.uk les-deglingos-activity-ball']::text[], 'none'),
    ('cat_soft_graspable_balls', 1, 1, 'visible', true, false, 'Best for living-room chase', 'Scrunch Ball', 'Scrunch', 'Adventure Toys', 'https://www.adventuretoys.co.uk/scrunch-ball/', NULL, '£12.99', 'in_stock', 'Toddler soft play ball (packable PVC)', 'A light 23cm soft PVC ball you inflate with a straw, grippy enough for toddler throws and indoor chase without a heavy sports ball bounce.', 'At sixteen to eighteen months, little adventures often mean a ball that rolls away and invites a toddle after it. Soft Scrunch weight keeps living-room chase kind on shins and shelves. Inflate it for the park bag when the same soft ball needs to travel without filling the boot.', 'Soft, light, chaseable; fits adventure cluster without sports-ball weight.', 'Needs inflate; supervise near roads outdoors.', 'buy', true, 'Easy wrap; colour choice on retailer page.', 'Skip a second soft ball if one already gets daily chase.', 'Inflate fully; adult inflate for first uses.', 'good', ARRAY['adventuretoys.co.uk/scrunch-ball']::text[], 'none'),
    ('cat_soft_graspable_balls', 2, 2, 'visible', true, true, 'Best for grasp and squash', 'Bigjigs Activity Balls', 'Bigjigs', 'Adventure Toys', 'https://www.adventuretoys.co.uk/big-jigs-activity-balls/', NULL, '£9.99', 'in_stock', 'Food-grade silicone activity balls', 'Food grade silicone activity balls with an open design so little fingers grasp, squash and pull a smaller ball in and out during floor play.', 'Busy hands at this age want something to grab as much as something to chase. Nested silicone balls make grasp and squash the game without a hard bounce across the room. Useful when mouthing is still strong and you want a wipe-clean ball that still rolls a short path.', 'Grasp-first soft ball for early toddling.', 'Shorter roll than a closed soft ball.', 'buy', true, 'Small box gift.', 'Pairs with one chase ball; not a duplicate Scrunch.', 'Supervise mouthing; check for tears.', 'good', ARRAY['adventuretoys.co.uk/big-jigs-activity-balls']::text[], 'none'),
    ('cat_soft_graspable_balls', 3, 3, 'visible', true, true, 'Best for soft fabric roll', 'Les Deglingos Melimelos Activity Ball', 'Les Deglingos', 'Toytastic', 'https://toytastic.co.uk/product/les-deglingos-activity-ball-melimelos-the-deer/', NULL, '£18.99', 'in_stock', 'From birth to around 18 months', 'A soft fabric activity ball with mirror, crinkle, rattle and teether tags, light enough for toddling hands to roll and fetch indoors.', 'Soft fabric balls keep chase play quiet when hard toys already fill the floor. Melimelos adds tags and a rattle so the roll still invites a crawl or toddle after it. Fits the upper end of the listed age window for sixteen to eighteen months without jumping to outdoor PVC.', 'Soft indoor roll with sensory hooks.', 'Age window tops out near 18m; watch wear on tags.', 'buy', true, 'Character gift with washable cover.', 'Different job from silicone or Scrunch.', 'Supervise tags and teether ring.', 'good', ARRAY['toytastic.co.uk Les Deglingos activity ball']::text[], 'none'),
    ('cat_soft_graspable_balls', 4, 4, 'visible', true, true, 'Best for spiral drop play', 'Quercetti Spiral Tower Baby Ball Run', 'Quercetti', 'Toytastic', 'https://toytastic.co.uk/product/quercetti-spiral-tower-06501/', NULL, '£19.99', 'in_stock', '1 year +', 'A snap together spiral tower with three large rattling balls that drop and roll down coloured ramps for toddler play that shows what happens next.', 'Some days chase is across the room; other days the ball needs a short path you can repeat. Large Quercetti balls stay easy to hold while the spiral makes roll and watch the job. Useful when you want soft graspable balls with a clear start and finish rather than open floor scatter alone.', 'Graspable balls with guided roll.', 'More setup than a single free ball.', 'buy', true, 'Strong cause-and-effect gift.', 'Not a second free chase ball if Scrunch already owned.', 'Large 4.5cm balls; still supervise.', 'good', ARRAY['toytastic.co.uk Quercetti Spiral Tower 06501']::text[], 'none'),
    ('cat_soft_graspable_balls', 5, 5, 'visible', true, true, 'Best for sound tower runs', 'Quercetti Migoga Tower Sound', 'Quercetti', 'Toytastic', 'https://toytastic.co.uk/product/quercetti-migoga-tower-sound/', NULL, '£25.99', 'in_stock', '18 months +', 'A 17-piece toddler ball run with three large sound balls that rattle, tinkle or shake as they roll down the tower track.', 'Eighteen months sits at the top of this band, and sound balls make each roll worth watching again. Migoga Tower Sound keeps balls oversized for toddler hands while the track gives a path you can repeat. Choose when open floor chase already works and you want listening plus rolling in one set.', '18m+ overlap; oversized balls.', 'Only overlaps at 18m; younger 16-17m may need help.', 'buy', true, 'Best near 18m birthday.', 'Do not buy both Quercetti towers unless space allows.', 'Adult help assembling; supervise.', 'good', ARRAY['toytastic.co.uk Quercetti Migoga Tower Sound']::text[], 'check_age_fit'),
    ('cat_stacking_pegboard', 1, 1, 'visible', true, false, 'Best for first ring stacks', 'Hape Stacking Jack', 'Hape', 'Adventure Toys', 'https://www.adventuretoys.co.uk/hape-stacking-jack/', NULL, '£9.25', 'in_stock', '12 months +', 'A wooden stacking character with chunky rings you dress from toes to hat in any order, sized for toddler hands learning size play.', 'Busy hands at sixteen to eighteen months want rings that fit, tip and try again on a short pole. Stacking Jack keeps pieces large and friendly without a stiff size rule. A clear first stack when you want wood quality at a small price before bigger wobble towers.', 'Classic ring stack for busy hands cluster.', 'Low stock signal on retailer; check before gift wrap.', 'buy', true, 'Small wooden gift.', 'Skip if a rainbow ring stacker already lives on the shelf.', 'Supervise; no small loose parts beyond rings.', 'good', ARRAY['adventuretoys.co.uk/hape-stacking-jack']::text[], 'none'),
    ('cat_stacking_pegboard', 2, 2, 'visible', true, true, 'Best for wobbly towers', 'Goki Rainbow Wobble Stacker', 'Goki', 'Toytastic', 'https://toytastic.co.uk/product/goki-rainbow-wobble-stacker/', NULL, '£21.99', 'in_stock', '1 year +', 'Six chunky rainbow wooden rings on a rounded base that makes wobbly towers as each piece is added, turning stacking into a balance try.', 'When steady poles seem too easy, a rocking base asks for slower hands and wobbly towers. The Goki rainbow stacker keeps rings big while the sway makes each place a small plan. Best once a flat stacker is already familiar and you want a tougher tower job.', 'Wobble stacking for progressing hands.', 'Harder than flat base; may frustrate cautious starters.', 'buy', true, 'Premium wooden gift.', 'Not a second flat ring set.', 'Supervise rocking play near table edges.', 'good', ARRAY['toytastic.co.uk goki-rainbow-wobble-stacker']::text[], 'none'),
    ('cat_stacking_pegboard', 3, 3, 'visible', true, true, 'Best for character wobble', 'Goki Stacking Bear Wobble Tower', 'Goki', 'Toytastic', 'https://toytastic.co.uk/product/goki-stacking-bear-wobble-tower/', NULL, '£18.99', 'in_stock', '1 year +', 'A wooden bear stacking tower with chunky pieces on a gentle wobble, inviting toddlers to build a short character stack on the floor.', 'Character stacks pull some toddlers in when plain rings look dull. The bear tower keeps the wobble idea while the face gives a finish to aim for. Choose when rainbow rings already sit on the shelf and you want a different wooden stack story.', 'Character wobble stack.', 'Max two Goki brands in Top 5 already used; still distinct SKU.', 'buy', true, 'Character wooden gift.', 'Pick rainbow OR bear wobble, not both.', 'Supervise.', 'good', ARRAY['toytastic.co.uk goki-stacking-bear-wobble-tower']::text[], 'none'),
    ('cat_stacking_pegboard', 4, 4, 'visible', true, true, 'Best for nest and tap', 'Hape Wooden Musical Instrument Stacking Set', 'Hape', 'Adventure Toys', 'https://www.adventuretoys.co.uk/hape-wooden-musical-instrument-stacking-set/', NULL, '£34.99', 'in_stock', '18 months +', 'Five nested wooden instruments that stack to tidy away, with a beater for drum, xylophone, cymbal, scratch and shaker play.', 'At the top of this band, stacking can mean nested boxes that also make sound. Hape nest and tap gives a tidy stack plus short music tries. Best near eighteen months when quieter ring stackers already feel too simple and you want sound with the stack.', 'Nesting stack with music.', '18m+ only overlaps band max.', 'buy', true, 'Larger gift box.', 'Second Hape SKU; still under brand max of two.', 'Supervise beater.', 'good', ARRAY['adventuretoys.co.uk hape-wooden-musical-instrument-stacking-set']::text[], 'check_age_fit'),
    ('cat_stacking_pegboard', 5, 5, 'visible', true, true, 'Best for spiral build towers', 'Quercetti Spiral Tower Baby Ball Run', 'Quercetti', 'Toytastic', 'https://toytastic.co.uk/product/quercetti-spiral-tower-06501/', NULL, '£19.99', 'in_stock', '1 year +', 'Snap together coloured spiral sections that build into a tall tower, then drop large balls for a short roll down the path.', 'Some stacking days are about building the tower itself, not only rings on a peg. Quercetti spiral sections click into a tall build toddlers can help assemble. Useful when wooden rings already feel finished and hands want a taller tower job with a roll at the end.', 'Tower build with pieces.', 'Also appears in soft-ball / ramp lists; ownership note across categories.', 'buy', true, 'Cause and effect gift.', 'Skip if already bought for ball-run play.', 'Supervise assembly.', 'good', ARRAY['toytastic.co.uk Quercetti Spiral Tower']::text[], 'none')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '16-18m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-24T11:05:59.832Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '16-18m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

